INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Egenskapen jag beundrar', 'Berätta om en egenskap hos din partner du beundrar', 'Tänk på en personlig egenskap som du verkligen uppskattar hos din partner. Det kan vara något stort eller litet. Berätta för din partner varför denna egenskap gör dig glad eller imponerad. Låt det vara autentiskt och specifikt.', 3, 1, 1);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Tacksamhetsbrevet', 'Skriv 3 saker du är tacksam för, läs upp', 'Skriv ner tre saker du är tacksam för som din partner gör eller är. Det kan vara praktiska saker, emotionella stöd eller små gester. Läs dem högt för varandra och dela vilken känsla som väcks.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Den osynliga insatsen', 'Nämn något vardagligt din partner gör som gör livet bättre', 'Ofta tar vi för givet de små saker som gör hvardagen bättre. Nämn något som din partner gör utan att göra mycket väsen av det. Kanske som de lagar mat, ordnar hemmet eller ger tröst när du behöver det.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Din bästa dag tillsammans', 'Berätta om en dag ni hade tillsammans som var särskilt bra', 'Tänk tillbaka på en dag som var extra speciell. Det behöver inte vara något dramatiskt - det kan vara en vanlig dag som kändes perfekt. Berätta varför den dagen var så bra och vad din partner gjorde som bidrog till det.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Kvalitetstidens värde', 'Berätta vad er tid tillsammans betyder för dig', 'Tänk på hur viktig den tid ni spenderar tillsammans är för dig. Berätta konkret om hur denna tid påverkar ditt välbefinnande och ditt förhållande till din partner.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Stödet jag behövde', 'Nämn ett tillfälle då din partner var där för dig', 'Tänk på en svår period eller stund i ditt liv då din partner var till stöd. Berätta om hur de var där för dig och vad det betydde. Uttryck din tacksamhet för detta.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Små gester, stor påverkan', 'Vilken liten sak gör din partner som smält ditt hjärta?', 'Tänk på något litet som din partner gör som alltid får dig att känna kärlek eller värme. Det kan vara ett leende, ett ord, eller en handling. Berätta om det och varför det betyder så mycket.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Växten vi vårdar tillsammans', 'Vad växer och blomstrar i ert förhållande?', 'Använd metaforen av växter och trädgårdar. Vilka "växter" växer i er relation - vilka positiva egenskaper, traditioner eller känslor blomstrar? Diskutera tillsammans vad ni gör för att få dem att växa.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Framsteg tillsammans', 'Vilka framsteg har ni gjort tillsammans?', 'Tänk på hur er relation har utvecklats över tiden. Vilka utmaningar har ni övervunnit tillsammans? Vilka mål har ni uppnått? Berätta för varandra och fira de framsteg ni gjort tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Den delen av dig jag älskar', 'Berätta om en del av dig själv som du tror din partner älskar', 'Det finns något hos dig som din partner värdesätter. Det kan vara din humor, din styrka, din sensitivitet eller något helt tredje. Berätta om det och låt din partner bekräfta eller utveckla vad de älskar hos dig.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Ritner vi tillsammans', 'Vilka ritner eller mönster finns i er relation?', 'Tänk på de positivt ritner som upprepas i er relation. Det kan vara små dagliga ritualer, hur ni löser konflikter eller hur ni celebrerar tillsammans. Berätta om dessa ritner och varför de är viktiga.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Styrkor vi kompletterar', 'Hur kompletterar dina styrkor varandras?', 'Var och en har olika styrkor. Hur fungerar er relation som ett team? Berätta om hur en styrka hos en av er balanserar eller kompletterar den andra. Hur gör detta förhållandet starkare?', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Ögonblick av enhet', 'Berätta om ett ögonblick då ni känd er helt förbundna', 'Tänk på ett eller flera ögonblick då ni har känt en djup enhet eller samhörighet. Det kan vara under en svår stund, en lycklig stund, eller något helt oväntat. Dela denna upplevelse tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Lyset du för in i mitt liv', 'Hur lyser din partner upp ditt liv?', 'Tänk på hur din partner bidrar till ditt välbefinnande. Berätta specifikt om hur de "lyser upp" dagen eller gör att du mår bättre. Det kan vara genom sitt sällskap, sitt skratt eller sin närvaro.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Insikten om kärlek', 'Vad har du lärt dig om kärlek genom att vara med din partner?', 'Vilka insikter om kärlek har du fått genom er relation? Vad har du lärt dig om dig själv som älskande person? Berätta om dessa lärdomar.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Spegeln i din syn', 'Hur ser din partner dig på ett sätt som gör dig glad?', 'Ofta kan vår partner se sidor av oss som vi inte alltid ser själva. Berätta om hur din partner ser dig och vilken effekt det har att de ser dig på detta sätt.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'Kärlekens små språk', 'Vilka små sätt visar ni kärlek till varandra?', 'Varje par har sitt eget sätt att visa kärlek på små sätt dagligen. Det kan vara genom beröring, ord eller gester. Identifiera dessa små "kärleksuttrck" och berätta om dem för varandra.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('appreciation', 'För mig betyder du...', 'Vad betyder din partner för dig? Fyll i fraser tillsammans', 'Turas om att fylla i: "För mig betyder du...". Förklara varför varje svar resonerar med dig. Låt svaren komma från hjärtat.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Drömresan', 'Om ni kunde resa vart som helst imorgon, vart?', 'Imaginera att ni kan resa vart som helst i världen på en drömsemester. Berätta om var ni skulle gå, vad ni skulle göra där och varför denna plats tilltalar er. Dela era drömresor med varandra.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Barndomsminnet', 'Berätta om ett lyckligt barndomsminne', 'Dela ett minne från din barndom som fortfarande värmer ditt hjärta. Det kan vara något stort eller litet, men något som återkommer i dina tankar och ger dig glädje när du tänker på det.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Om 5 år', 'Hur ser ert liv ut om 5 år?', 'Låt er fantasi flyga. Var är ni på vägen? Vad gör ni? Vilka är de små och stora förändringar ni önskar? Delar erat visioner och diskutera hur ni kan arbeta tillsammans för att göra dem till verklighet.', 5, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Dina okända delar', 'Vilka delar av dig skulle du vilja att din partner kände bättre?', 'Vi alla har delar av oss som är dolda eller mindre kända för vår partner. Vilka sidor av dig själv skulle du vilja att din partner förstod eller kände bättre? Berätta om dessa dolda delar.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Världen genom dina ögon', 'Vad ser du i världen som gör dig nyfiken?', 'Berätta om något i världen som väcker din nyfikenhet och undran. Det kan vara naturvetenskapligt, kulturellt, filosofiskt eller något helt tredje. Dela din passion för att förstå detta.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Din hemligaste dröm', 'Vilken är din hemligaste dröm som du aldrig riktigt berättat om?', 'Vi alla har drömmar vi inte alltid delar. Vilken är en dröm som du bär på men sällan talar om för andra? Våga dela denna dröm med din partner och berätta varför den är viktig för dig.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Framtida äventyr', 'Vad skulle du vilja utforska tillsammans med din partner?', 'Tänk på nya erfarenheter, färdigheter eller platser ni gärna skulle vilja utforska tillsammans. Det kan vara en ny hobby, ett nytt land eller en ny utmaning. Dela dessa äventyrliga drömmar.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Livsfilmens nästa kapitel', 'Vad skulle hända i nästa kapitel av er livshistoria?', 'Om er liv var en film, vad skulle vara nästa stora utveckling? Vilken riktning skulle ni vilja att filmen tog? Diskutera de intressanta möjligheterna tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Tankar du inte delar ofta', 'Vilka tankar går genom ditt huvud som du inte alltid delar?', 'Vi alla har många tankar som vi inte delar med andra. Vilka tankar gör att du är du? Det kan vara filosofiska, dagdrömmar eller reflektioner. Dela några av dessa med din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Din underliga intresse', 'Vilken är en intresse du har som få vet om?', 'Vi all har intresssen som kanske inte alla förstår eller vet om. Det kan vara något nischat eller specifikt som du brinner för. Berätta om denna passion och varför den betyder något för dig.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Tiden tillbaka', 'Om du kunde gå tillbaka i tiden, vad skulle du vilja att din ungare själv visste?', 'Tänk på visdom eller lektioner du lärt dig. Vilka skulle du vilja berätta för din yngre själv? Dela dessa lärdomar med din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Magiska möjligheter', 'Om du hade en magisk kraft, vilken skulle den vara?', 'Låt fantasin flyga. Vilken kraft skulle du vilja ha och varför? Hur skulle denna kraft förändra ditt liv eller världen? Diskutera dessa magiska möjligheter tillsammans.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Människor du beundrar', 'Vilka personer beundrar du och varför?', 'Tänk på människor - kända eller okända - som du beundrar. Vad gör dem beundransvärda? Hur influerar de dina värderingar eller drömmar? Dela dessa influenser med din partner.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Det du vill förstå', 'Vad i livet skulle du vilja förstå bättre?', 'Vilka mysterier eller frågor gör att du undrar? Det kan vara om relationer, universum, människor eller något helt tredje. Dela dessa tankar och utforska dem tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Din idealvärld', 'Vad skulle din idealvärld se ut som?', 'Skapa tillsammans en bild av er idealvärld. Vilka värden skulle dominera? Vilka förhållanden mellan människor? Hur skulle samhället fungera? Drömma tillsammans om denna bättre värld.', 5, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Lärdomar från berättelser', 'Vilken bok, film eller berättelse har påverkat dig?', 'Vilka berättelser från böcker, filmer eller andras liv har gjort intryck på dig? Vilka lektioner eller perspektiv tog du med dig? Berätta om dessa influenser.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Det icke uttryckta', 'Vad skulle du vilja säga men aldrig vågar?', 'Vi alla bär på ord och tankar som vi inte alltid uttrycker. Vilka ord eller tankar skulle du vilja säga högt men på något sätt varit rädd för det? Våga säga dem nu till din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('curiosity', 'Livets stora frågor', 'Vilka är dina största livsfrågor?', 'Vilka existentiella eller livsbetydande frågor fyller ditt sinne? Vem är jag? Vad är mitt syfte? Vad betyder ett gott liv? Dela dessa djupa frågor med din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Första gången', 'Berätta om första gången ni sågs', 'Tänk tillbaka på den första gången ni möttes. Vad gjorde intryck på dig? Vad tänkte eller kände du? Var du nervös, glad, förvånad? Dela dessa första intryck tillsammans och se hur de skiljer sig åt.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Bästa semestern', 'Återupplev ert bästa semesterminne', 'Vilken semester eller resa tillsammans var din favorit? Var var ni? Vad gjorde det särskilt? Diskutera det tillsammans och låt minnena väcka gamla känslor av glädje och äventyr.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Soundtracket', 'Vilken låt påminner om er relation?', 'Finns det en eller flera låtar som för dig tillbaka till ert förhållande? Det kan vara en låt ni älskade tillsammans, en som spelades på en viktig dag eller en som bara beskriver er kärlekshistoria. Dela dessa låtar och varför de betyder något.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Det första ömsesidiga skrattet', 'Berätta om första gången ni båda skrattade tillsammans', 'Vilken var första gången ni båda skrattade på något? Det var väl en befriande och varm upplevelse. Tänk tillbaka på hur det kändes och varför det var viktigt. Berätta om detta minne.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Händelsen som förändrade allt', 'Berätta om en händelse som förändrade er relation', 'Det finns ofta en viss händelse eller moment som markerade en förändring i en relation. Kanske när ni insåg att det var allvar eller när något utmanade er. Berätta om denna vändpunkt tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Växten från sådd till blomst', 'Hur växte er kärlekshistoria från början?', 'Tänk på hur er relation utvecklades från början. Det var säkert långsamt och stegvis. Berätta om dessa små steg och hur de tillsammans byggde något starkt.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Överraskande ögonblick', 'Berätta om en gång du överraskades av din partner', 'Har din partner någon gång gjort något som överraskade eller rörd dig? Det kan vara något enkelt eller något genomtänkt. Berätta om denna överraskning och hur det fick dig att känna.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Konversationen som änäde allt', 'Finns det ett samtal som var särskilt viktigt?', 'Ibland är det ett samtal som gör att du förstår något nytt eller kände något nytt för din partner. Berätta om ett samtal som var särskilt betydelsefullt eller transformerande.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Det andra vi skadade', 'Berätta om en gång vi skadade varandra och läkte', 'Det är naturligt att vi skadar varandra ibland. Finns det en gång då ni båda skadade varandra men läkte? Berätta om denna process och hur ni kom igenom det tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Platsen som betyder något', 'Finns det en plats som betyder något speciellt för er?', 'Ofta finns det en plats - ett café, en strand, ett rum - som är speciell för ett par. Vilken plats betyder något för er? Varför är denna plats speciell? Berätta tillsammans om denna plats.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Ceremonin vi skapade', 'Vilka ceremonier eller ritualer skapade vi tillsammans?', 'Över tiden skapar par ofta små ceremoni eller ritualer som är bara deras. Det kan vara hur ni firar, hur ni hälsar eller något helt tredje. Berätta om dessa speciella ritualer.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Krisen vi klarat', 'Berätta om en kris ni klarat tillsammans', 'Alla par möter utmaningar. Vilken var en svår tid ni gick genom tillsammans? Hur klorte ni det och vad lärde ni? Berätta om denna styrka ni visa tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Den osäkra tiden', 'Berätta om en tid då ni var osäker på förhållandet', 'Många par går genom perioder av osäkerhet. Var det en tid då du undrade? Vad hjälpte er att finna vägen tillbaka? Berätta om denna process tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Skrattets hemlighet', 'Vilka inre skämt delar bara ni två?', 'De flesta par utvecklar inre skämt och referenser som bara de förstår. Vilka är några av era? De är ofta både enkla och djupt meningsfulla. Dela dessa och skratta tillsammans.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Bilden som säger allt', 'Vilken foto från er tillsammans betyder mest för er?', 'Ofta finns det ett foto eller en bild som fångat något väsentligt om er relation. Vilken bild betyder mest för er och varför? Diskutera tillsammans vad denna bild representerar.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Ord som hängde kvar', 'Vilka ord från din partner har hängde kvar hos dig?', 'Ibland säger vår partner något som vi aldrig glömmer. Ord som var tröstande, inspirerande eller enkelt viktiga. Vilka ord från din partner betyder något för dig? Berätta om dessa ord.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Tillväxten tillsammans', 'Hur har vi växt tillsammans genom åren?', 'Tänk på hur er relation har djupt eller mognats över tiden. Vad har ni lärt er om varandra? Vilka nya sidor har ni sett? Berätta om denna växande tillsammans.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Bytte roll', 'Om ni bytte roller en dag, vad skulle du göra?', 'Imaginera att ni byter roll för en dag. Vad skulle du göra i hans/hennes skor? Vilka motsättningar och utmaningar skulle du möta? Diskutera tillsammans hur svårt eller lätt det skulle vara att leva en dag som din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Önskelistan', 'Berätta om en sak du önskar att din partner visste', 'Vi önskar ofta att vår partner förstod något specifikt om oss, våra behov eller våra drömmar. Vilken är en sak du skulle vilja att din partner visste? Berätta detta nu.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Tack-kedjan', 'Turas om att tacka för specifika saker', 'Turas om. Den ena börjar med att tacka för något specifikt, den andra svarar med att tacka för något. Fortsätt denna kedja av tacksamhet och se hur många ni kan komma på.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Det jag behöver från dig', 'Vad behöver du från din partner för att vara lycklig?', 'Vi alla har behov som behöver uppfyllas för att vi ska må bra. Vilka är dina viktigaste behov i relation? Kan vara emotionella, praktiska eller något helt tredje. Dela dessa behov med din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Mitt behov av förståelse', 'Berätta något du tror din partner inte helt förstår om dig', 'Det finns ofta något hos oss som vi tror att vår partner inte helt förstår. Det kan vara vår rädsla, vår passion eller vår sårbarhet. Berätta om detta och förklara varför det är svårt att förstå.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Delen av dig jag inte förstår', 'Berätta varligt om något du inte förstår hos din partner', 'Alla par har saker de inte helt förstår hos varandra. Det är okej att inte förstå allt. Säg varligt något du inte förstår och bjud in din partner att förklara.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Mitt sätt att älska', 'Berätta hur du älskar och vad du behöver för att känna dig älskad', 'Vi älskar alla på olika sätt. Vad är ditt sätt att älska? Hur visar du kärlek? Och vad behöver du för att känna att du blir älskad? Berätta om detta för din partner.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Det jag ger', 'Vad bidrar du med till vår relation?', 'Vi alla bidrar med något unikt till vår relation. Det kan vara praktiska saker, emotionellt stöd eller något helt tredje. Vilka är dina viktiga bidrag? Berätta om detta med stolthet.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Att ge utan att förvänta', 'Berätta om en gång du gav något utan att förvänta något tillbaka', 'Ibland ger vi något helt utan att förvänta något i gengäld. Det kan vara tid, stöd eller gåvor. Berätta om en sådan gång och hur det kändes att ge utan att förvänta något.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Balansen vi söker', 'Hur balanserar vi ge och ta i vår relation?', 'Alla relationer behöver balans mellan att ge och ta. Hur upplever du denna balans? Är det bra? Behöver något förändras? Diskutera detta tillsammans och sök lösningar tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Mina behov när jag är svag', 'Vad behöver du när du är på din svagaste?', 'Vi alla har stunder då vi är svaga eller sårbar. Vad behöver du då? Är det tystnad, omfamning, ord eller något helt tredje? Berätta om detta så att din partner kan vara till bättre stöd.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Gåvan jag vill ge', 'Vilken gåva skulle du vilja kunna ge din partner?', 'Ofta önskar vi att vi kunde ge något större till vår partner. Det kan vara praktiskt, emotionellt eller helt metaforiskt. Vilken gåva skulle du vilja ge och varför?', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Andedrag tillsammans', 'Berätta om stunder då ni andades tillsammans', 'Ibland finns det stunder då ni är i perfekt synkronisering. Ni förstår utan ord, ni andas tillsammans. Berätta om sådana ögonblick och hur de känns.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Det du behöver förlåtelse för', 'Berätta om något du önskar förgivit för', 'Vi gör alla misstag. Finns det något du önskar att din partner förlät dig för? Berätta om detta, be om förlåtelse och låt denna konversation läka något.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Försoning', 'Diskutera en senaste konflikt och hur ni löste den', 'Tänk på en senaste gång ni hade en konflikt. Hur löste ni den? Vad kunde ni ha gjort annorlunda? Diskutera detta och se hur ni kan åtgärda gamla sår.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Framtida tillsammans', 'Vilka mål skulle vi vilja uppnå tillsammans?', 'Tänk på vilka mål ni skulle vilja uppnå tillsammans framöver. Det kan vara stora eller små mål. Vilka drömmar för ni tillsammans? Diskutera dessa och gör en plan tillsammans.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Sten, sax, påse deluxe', 'Spela med egna regler', 'Spela det klassiska spelet sten, sax, påse men med era egna regler. Kanske segraren får en önskan uppfylld eller förloraren måste göra något roligt. Kom på egna slagord eller konsekvenserr och skratta tillsammans.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', '20 frågor', 'Tänk på ett minne, partnern gissar', 'En tänker på ett speciellt minne ni delar. Den andra får ställa upp till 20 ja-eller-nej-frågor för att gissa vilket minne det är. Skratta åt hur väl den andra känner dig.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Dansa i köket', 'Sätt på en låt och dansa spontant', 'Sätt på en låt som ni båda älskar. Dansa spontant och glöm all själekritik. Det är inte om att kunna dansa - det är om att skratta och ha roligt tillsammans.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Rollspel', 'Spela olika scenarion tillsammans', 'Välj ett scenario - kanske ett första möte på nytt, ett hemligt möte eller något helt fantastiskt. Rollspela detta tillsammans med humor och kreativitet. Skratta åt det absurda.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Quiz om varandra', 'Testa hur väl ni känner varandra', 'Ställ frågor som "Vad är min favoritmat?", "Vilken färg älskar jag?", "Vad var mitt första jobba?" osv. Se hur många ni kan rätt. Diskutera varför ni missade vissa och skratta åt felsluten.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Makalöst spel', 'Kombinera två ord och skapa nya ord', 'Välj två ord och försök skapa nya ord genom att kombinera dem. T.ex. "katt" + "hund" = "katthund"? Vem kan komma på det roligaste ordet?', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Minne-spel', 'Ordna småsaker och kom ihåg dem', 'Samla några småsaker från hemmet. Organisera dem på ett bord, låt din partner titta på dem i 30 sekunder, täck dem sedan till. Hur många kan de komma ihåg?', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Forbjudna ordet', 'Konversation utan att säga ett specifikt ord', 'Välj ett ordförbjudet ord (t.ex. "älska", "glad", "du"). Prata i 5 minuter utan att säga detta ord. Det är svårare än du tror!', 3, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Rolig fremtoning', 'Gör dumma ansikten åt varandra', 'Bli inte bashfull. Gör de roligaste ansikterna ni kan åt varandra. Vem kan få den andra att skratta hårdast?', 2, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Ljugt eller sanning', 'Berätta historier som kan vara sant eller falskt', 'En berättar en historia som kan vara sant eller falskt. Den andra gissar. Berätta roliga eller underliga historier som gör det svårt att veta.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Ord-kedje', 'Turas om att säga ord relaterade till föregående', 'En säger ett ord. Den andra säger ett ord relaterat till det. Fortsätt denna ord-kedje och se hur långt ni kan komma innan ni blir osäker på kopplningen.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Simulera känslor', 'Uttrycka känslor bara genom ansiktet', 'En uttrycker en känsla bara genom sitt ansikte. Den andra gissar vilken känsla det är. Gör det så extravagant och humoristisk som möjligt.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Tävling i sinnena', 'Blindfold-spel för en eller båda', 'Blindfold en av er och prova något - en mat, en doft, en känsla. Kan de gissa vad det är? Gör det roligt och överraskande.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Cirkus-trick', 'Kom på dumt trick eller joking', 'Kom på dumma trick eller skämt för varandra. Det behöver inte vara bra - det kan vara riktigt dåligt humor som får er att skratta.', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Kåserier', 'Överdriv något om varandra på ett lustigt sätt', 'Skapa överdragna versioner av varandra baserat på era quirks. "Du älskar kaffe så mycket att jag tror du är kaffe." Gör det översittat och absurt.', 3, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Gissa vad jag tänker', 'Mental telepati-spel', 'Tänk intensivt på något (en färg, ett djur, ett nummer). Din partner försöker läsa dina tankar genom att ställa frågor eller bara gissa. Hur många kan de få rätt?', 3, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Samarbets-utmaning', 'Lösa ett pussel eller problem tillsammans', 'Ta ett pussel, ett ordlek eller en utmaning. Arbeta tillsammans för att lösa det. Det är inte en tävling - det är om att ha roligt och samarbeta.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('play', 'Framtidas versioner', 'Berätta roliga eller absurda framtida scenarier', 'Berätta absurda eller roliga scenarier om er framtid tillsammans. "Om 10 år är vi nu på Månen och du jobbar som astronaut..." Gör det så silly som möjligt.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('memories', 'Minneskapseln', 'Skapa tillsammans en minneskapseln med foton och småsaker', 'Samla några småsaker från er tid tillsammans - foton, biljetter, små presentar. Lägg dem i en låda eller skrin. Diskutera varje grej och vad det betyder för er gemensamma historia.', 4, 1, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Jämlikheten vi skapar', 'Hur skapar vi en jämlik relation?', 'Vilka värderas båda två är viktiga för er jämlikhet? Hur försäkrar ni att båda röster hörs och att båda behov beaktas? Diskutera detta.', 4, 2, NULL);
INSERT INTO exercises (category, title, description, instructions, duration_minutes, difficulty, day_number) VALUES
('reciprocity', 'Framtidsvision tillsammans', 'Skapa tillsammans en gemensam vision för framtiden', 'Vad önskar ni tillsammans för er framtid? Vilka värden vill ni dela? Vilka upplevelser vill ni ha tillsammans? Skapa tillsammans denna vision och gör den konkret.', 4, 2, NULL);
